// Cypress Testing Framework with Docker and Screenshot Capture

// Setup Docker
const { exec } = require('child_process');

// Run Docker container
exec('docker run -it --rm -p 3000:3000 cypress/base:latest', (err, exitCode) => {
  if (err) {
    console.error('Error running Docker container:', err);
    return;
  }

  // Run Cypress tests
  exec('cypress run -b --spec specs/my-tests.js', (err, exitCode) => {
    if (err) {
      console.error('Error running Cypress tests:', err);
      return;
    }

    // Capture screenshot and save it
    const screenshotPath = `screenshots/${Date.now()}.png`;
    exec(`cypress capture ${screenshotPath}`, (err, exitCode) => {
      if (err) {
        console.error('Error capturing screenshot:', err);
        return;
      }
    });
  });
});

// Run the framework
const framework = new Cypress({
  basePath: 'cypress',
  specPatterns: ['**/*.js'],
  screenshotCapture: true,
  screenshotCaptureFolder:'screenshots',
});

framework.configure(() => {
  framework.beforeEach(() => {
    // Run Docker container before each test
    exec('docker run -it --rm -p 3000:3000 cypress/base:latest', (err, exitCode) => {
      if (err) {
        console.error('Error running Docker container:', err);
      }
    });
  });

  framework.afterEach(() => {
    // Stop Docker container after each test
    exec('docker stop cypress/base:latest', (err, exitCode) => {
      if (err) {
        console.error('Error stopping Docker container:', err);
      }
    });
  });
});

framework.run();
```

